import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface QuizScore {
  module: string;
  score: number;
}

interface WidgetData {
  completedModules: number;
  totalModules: number;
  quizScores: QuizScore[];
  timeSpentTrend: number[];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const { completedModules, totalModules, timeSpentTrend } = widgetData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#2D2D2D' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFFFFF' }}>
              Course Progress
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Modules Completed: {completedModules} / {totalModules}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 100 }}>
            <LineChart
              series={[
                {
                  data: timeSpentTrend,
                  color: '#4A90E2',
                  curve: 'natural',
                  showMark: false,
                },
              ]}
              xAxis={[{ data: timeSpentTrend.map((_, i) => i), hide: true }]}
              yAxis={[{ hide: true }]}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
              sx={{
                '& .MuiLineElement-root': {
                  strokeWidth: 2,
                },
              }}
            />
          </Box>

          <Stack direction="row" spacing={0.5}>
            {widgetData.quizScores.slice(0, 3).map((quiz, index) => (
              <Box key={index} sx={{ bgcolor: '#37474F', borderRadius: 1, px: 1, py: 0.5 }}>
                <Typography variant="caption" sx={{ color: '#B0BEC5' }}>
                  {quiz.module}
                </Typography>
                <Typography variant="body2" sx={{ color: '#FFFFFF', fontWeight: 500 }}>
                  {quiz.score}%
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
